function solve(s: string, order: number[], k: number): number {
    const n = s.length;
    const replaced = new Array(n).fill(false);
    let validCount = 0;

    // Function to calculate the number of valid substrings
    function countValidSubstrings() {
        validCount = 0;
        for (let i = 0; i < n; i++) {
            for (let j = i; j < n; j++) {
                let hasStar = false;
                for (let m = i; m <= j; m++) {
                    if (replaced[m]) {
                        hasStar = true;
                        break;
                    }
                }
                if (hasStar) {
                    validCount++;
                }
            }
        }
    }

    // Binary search for the minimum time t
    let left = 0, right = n;
    let answer = -1;

    while (left <= right) {
        const mid = (left + right) >> 1;
        // Replace first mid positions in order
        for (let i = 0; i < mid; i++) {
            replaced[order[i]] = true;
        }
        // Calculate the number of valid substrings
        countValidSubstrings();
        // Check if it's active
        if (validCount >= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
        // Reset replaced array for next iteration
        replaced.fill(false);
    }

    return answer;
}
